+import { Recur } from './recur.ts';
+
+/** @internal */
+export function resolveRecur<TSchema extends object>(
+  schema: TSchema,
+  recursiveSchema: object
+): TSchema {
+  const cache = new Map<object, unknown>();
+
+  const resolve = (value: unknown): unknown => {
+    if (value === Recur) return recursiveSchema;
+    if (!value || typeof value !== 'object') return value;
+    if (cache.has(value)) return cache.get(value);
+    if (Array.isArray(value)) {
+      const copy: unknown[] = [];
+      cache.set(value, copy);
+      for (const item of value) copy.push(resolve(item));
+      return copy;
+    }
+    const copy = Object.create(Object.getPrototypeOf(value)) as object;
+    cache.set(value, copy);
+    const descriptors = Object.getOwnPropertyDescriptors(value);
+    for (const key of Reflect.ownKeys(descriptors)) {
+      const descriptor = descriptors[key];
+      if ('value' in descriptor) descriptor.value = resolve(descriptor.value);
+    }
+    Object.defineProperties(copy, descriptors);
+    return copy;
+  };
+
+  return resolve(schema) as TSchema;
+}
